const ctx = require('./.forge/project-context.json');
// Validate required fields
const errors = [];
if (!ctx.project || !ctx.project.name || typeof ctx.project.name !== 'string' || ctx.project.name.trim() === '') errors.push('project.name is missing or empty');
if (!ctx.project || !ctx.project.prefix || typeof ctx.project.prefix !== 'string' || ctx.project.prefix.trim() === '') errors.push('project.prefix is missing or empty');
if (!Array.isArray(ctx.entities)) errors.push('entities must be an array');
if (!Array.isArray(ctx.impactCategories)) errors.push('impactCategories must be an array');
if (!Array.isArray(ctx.technicalDebt)) errors.push('technicalDebt must be an array');
if (!Array.isArray(ctx.skillWiring)) errors.push('skillWiring must be an array');
if (!ctx.verification || typeof ctx.verification.test !== 'string') errors.push('verification.test is missing');
if (errors.length > 0) {
  console.error('Validation errors:', errors);
  process.exit(1);
} else {
  console.log('project-context.json validated OK');
}
